const item = $input.first();
const source = item.json ?? {};
const templateConfig = source.templateConfig ?? {};
const receivedAt = source.receivedDateTime ?? source.receivedDate ?? source.createdDateTime ?? new Date().toISOString();
const subject = String(source.subject ?? '');

function escapeODataString(value) {
  return String(value).replace(/'/g, "''");
}

function getConfig(path, fallback) {
  const nestedValue = path.split('.').reduce((value, key) => value?.[key], templateConfig);
  if (nestedValue !== undefined && nestedValue !== null && nestedValue !== '') return nestedValue;

  const dottedValue = source[`templateConfig.${path}`];
  if (dottedValue !== undefined && dottedValue !== null && dottedValue !== '') return dottedValue;

  return fallback;
}

function splitList(value, fallback) {
  return String(value || fallback)
    .split(',')
    .map(item => item.trim().toLowerCase())
    .filter(Boolean);
}

const legalForms = new Set(splitList(getConfig('clientSubjectHintLegalForms', 'gmbh,ug,ag,kg,ohg,gbr,e.k.')));

function extractCompanyNameFromSubject(value) {
  const cleaned = String(value ?? '').replace(/[\[\](){},;:]/g, ' ');
  const tokens = cleaned.split(/\s+/).filter(Boolean);
  const leadingNoise = new Set(['invoice', 'rechnung', 'beleg', 'document', 'dokument', 'for', 'für', 'from', 'von', 'client', 'kunde', 'attachment', 'anhang']);

  for (const [index, token] of tokens.entries()) {
    if (!legalForms.has(token.toLowerCase())) continue;

    const start = Math.max(0, index - 3);
    const candidateTokens = tokens.slice(start, index + 1);
    while (candidateTokens.length > 1 && leadingNoise.has(candidateTokens[0].toLowerCase())) {
      candidateTokens.shift();
    }

    return candidateTokens.join(' ').trim();
  }

  return null;
}

const fallbackClientFilter = getConfig('clientFilterFallback', 'status eq active');
const companyNameFromSubject = extractCompanyNameFromSubject(subject);
const datevClientFilter = companyNameFromSubject
  ? `status eq active and name eq '${escapeODataString(companyNameFromSubject)}'`
  : fallbackClientFilter;

return [
  {
    json: {
      ...source,
      email: {
        messageId: source.id,
        receivedAt,
        hasAttachments: source.hasAttachments === true,
      },
      demoConfig: {
        datevClientFilter,
        clientMatchHint: {
          source: companyNameFromSubject ? 'subject_company_name' : 'fallback_review',
          companyName: companyNameFromSubject,
        },
        reviewCategory: getConfig('reviewCategory', 'DMS_REVIEW_REQUIRED'),
        archivedCategory: getConfig('archivedCategory', 'DMS_ARCHIVED'),
        dms: {
          classId: getConfig('dms.classId', '1'),
          className: getConfig('dms.className', 'Dokument'),
          domainId: getConfig('dms.domainId', '1'),
          domainName: getConfig('dms.domainName', 'Mandanten'),
          folderId: getConfig('dms.folderId', '2'),
          folderName: getConfig('dms.folderName', '<Keine Angabe>'),
        },
      },
    },
    binary: item.binary,
  },
];

const configItem = $('Demo - Configure processing').first();
const source = configItem.json;
const clients = $input.all()
  .map(item => item.json ?? {})
  .filter(client => client.id);

const uniqueClients = Array.from(new Map(clients.map(client => [client.id, client])).values());
const status = uniqueClients.length === 1 ? 'exact' : uniqueClients.length === 0 ? 'not_found' : 'multiple';

return [
  {
    json: {
      ...source,
      client: uniqueClients[0] ?? null,
      clientMatch: {
        status,
        count: uniqueClients.length,
        filter: source.demoConfig.datevClientFilter,
        checkedAt: new Date().toISOString(),
      },
      review: status === 'exact' ? null : {
        category: source.demoConfig.reviewCategory,
        reason: status === 'not_found'
          ? 'No DATEV client matched the demo filter.'
          : 'More than one DATEV client matched the demo filter.',
      },
    },
  },
];

const emailItem = $('Outlook - New email with attachments').first();
const evaluated = $('Demo - Evaluate client match').first().json;
const config = evaluated.demoConfig;
const binaries = emailItem.binary ?? {};
const skipped = [];

function normalizeExtension(binary, fileName) {
  const fromBinary = String(binary.fileExtension ?? '').toLowerCase().replace('.', '');
  if (fromBinary) return fromBinary;

  const parts = String(fileName ?? '').split('.');
  return parts.length > 1 ? parts.pop().toLowerCase() : '';
}

function parseFileSize(value) {
  if (typeof value === 'number') return value;
  if (!value) return null;

  const text = String(value).trim().toLowerCase().replace(',', '.');
  const number = Number.parseFloat(text);
  if (!Number.isFinite(number)) return null;
  if (text.includes('mb')) return number * 1024 * 1024;
  if (text.includes('kb')) return number * 1024;
  return number;
}

function skipReason(binary, fileName, extension) {
  const ignoredExtensions = new Set(['ics', 'vcf']);
  if (ignoredExtensions.has(extension)) return `Ignored .${extension} attachment`;

  const mimeType = String(binary.mimeType ?? '').toLowerCase();
  const isImage = mimeType.startsWith('image/') || ['png', 'jpg', 'jpeg', 'gif', 'webp'].includes(extension);
  const size = parseFileSize(binary.fileSize);
  const looksLikeSignature = /^(image|logo|signature|signatur)[-_]?[0-9]*/i.test(fileName)
    || /(logo|signature|signatur|facebook|linkedin|twitter|instagram|banner)/i.test(fileName);

  if (binary.isInline === true) return 'Inline attachment';
  if (isImage && looksLikeSignature && (size === null || size <= 102400)) return 'Likely email signature image';
  return null;
}

const receivedAt = evaluated.email?.receivedAt ?? new Date().toISOString();
const receivedDate = new Date(receivedAt);
const periodDate = Number.isNaN(receivedDate.getTime()) ? new Date() : receivedDate;
const baseJson = {
  email: evaluated.email,
  client: evaluated.client,
  demoConfig: config,
  dmsPeriod: {
    year: periodDate.getFullYear(),
    month: periodDate.getMonth() + 1,
    source: Number.isNaN(receivedDate.getTime()) ? 'processing_date' : 'email_received_date',
    receivedAt,
    processedAt: new Date().toISOString(),
  },
};

const archiveItems = [];
for (const [binaryKey, binary] of Object.entries(binaries)) {
  const fileName = binary.fileName || binaryKey;
  const extension = normalizeExtension(binary, fileName);
  const reason = skipReason(binary, fileName, extension);

  if (reason) {
    skipped.push({ binaryKey, fileName, reason });
    continue;
  }

  archiveItems.push({ binaryKey, binary, fileName, extension });
}

if (archiveItems.length === 0) {
  return [
    {
      json: {
        ...baseJson,
        attachment: {
          shouldArchive: false,
          skippedAttachments: skipped,
          skippedCount: skipped.length,
        },
        review: {
          category: config.reviewCategory,
          reason: 'No archiveable document attachments were found after filtering.',
        },
      },
    },
  ];
}

return archiveItems.map((attachment, index) => ({
  json: {
    ...baseJson,
    attachment: {
      shouldArchive: true,
      binaryKey: attachment.binaryKey,
      fileName: attachment.fileName,
      extension: attachment.extension,
      mimeType: attachment.binary.mimeType ?? null,
      fileSize: attachment.binary.fileSize ?? null,
      index: index + 1,
      total: archiveItems.length,
      skippedAttachments: skipped,
      skippedCount: skipped.length,
    },
  },
  binary: {
    data: attachment.binary,
  },
}));

const createdDocuments = $input.all();
const attachments = $('Attachments - Split and filter documents').all()
  .filter(item => item.json.attachment?.shouldArchive === true);
const first = attachments[0]?.json ?? {};

return [
  {
    json: {
      email: first.email,
      archive: {
        category: first.demoConfig?.archivedCategory ?? 'DMS_ARCHIVED',
        documentsCreated: createdDocuments.length,
        attachmentsProcessed: attachments.length,
        completedAt: new Date().toISOString(),
      },
    },
  },
];
